const items = $input.all();
const results = [];

// Duyệt từng bài viết RSS
for (const item of items) {
  const post = item.json;

  results.push({
    json: {
      // Thông tin chính
      tieuDe: post.title || 'Không có tiêu đề',
      urlBaiViet: post.link || '',
      nguonTin: 'Google News - ' + (post.creator || 'Nguồn tin'),
      ngayDang: post.pubDate || post.isoDate || new Date().toISOString(),

      // Dữ liệu RSS gốc (để tham khảo)
      rss_description: post.contentSnippet || post.description || '',
      rss_content: post.content || ''
    }
  });
}

// Log số lượng bài lấy được
console.log('Tìm thấy', results.length, 'bài viết từ RSS');

// Trả kết quả cho node tiếp theo
return results;

// Lấy toàn bộ item đầu vào
const items = $input.all();

// ================== DEBUG ==================
console.log('=== DEBUG DỮ LIỆU ĐẦU VÀO ===');
items.forEach((item, i) => {
  console.log(`Item ${i}:`, Object.keys(item.json));
});

// ================== 1. BÀI VIẾT CŨ (Sheets) ==================
const oldArticles = items.filter(item =>
  item.json.TieuDe && item.json.UrlBaiViet
);
console.log('[CŨ] Tổng bài từ Sheets:', oldArticles.length);

// ================== 2. BÀI VIẾT MỚI ==================
const newArticles = items.filter(item =>
  item.json.tieuDe && item.json.urlBaiViet
);
console.log('[MỚI] Tổng bài mới:', newArticles.length);

// Không có bài mới → kết thúc
if (newArticles.length === 0) {
  console.log('Không có bài viết mới');
  return [];
}

// ================== 3. TẠO DANH SÁCH LINK CŨ ==================
const oldLinks = new Set();

for (const item of oldArticles) {
  const link = item.json.UrlBaiViet?.trim().toLowerCase();
  if (link) oldLinks.add(link);
}

console.log('📌 Tổng link cũ:', oldLinks.size);

// ================== 4. LỌC BÀI KHÔNG TRÙNG ==================
const uniqueArticles = [];

for (const item of newArticles) {
  const article = item.json;
  const title = article.tieuDe || 'Không có tiêu đề';
  const link = article.urlBaiViet?.trim().toLowerCase();

  if (link && oldLinks.has(link)) {
    console.log('TRÙNG LINK:', title);
    continue;
  }

  console.log('✅ BÀI MỚI:', title);
  uniqueArticles.push(item);
}

// ================== 5. KẾT QUẢ ==================
console.log(
  `KẾT QUẢ: ${uniqueArticles.length}/${newArticles.length} bài mới`
);

// Trả về bài không trùng
return uniqueArticles;

const ketQua = [];

for (const item of items) {
  const data = item.json;
  const ngayXuLy = new Date().toLocaleString('vi-VN');

  // Hàm lấy giá trị an toàn
  const getField = (obj, possibleKeys, defaultValue = '') => {
    if (!obj) return defaultValue;
    for (const key of possibleKeys) {
      if (obj[key] !== undefined && obj[key] !== null && obj[key] !== '') return obj[key];
    }
    return defaultValue;
  };

  // Xác định trường chứa output của AI (n8n thường để ở output, text, hoặc content)
  let rawOutput = getField(data, ['output', 'text', 'message', 'content'], '');
  let parsed = {};

  if (rawOutput && typeof rawOutput === 'string' && rawOutput.trim() !== '') {
    let cleaned = rawOutput.trim();

    // 1. Loại bỏ markdown code block (```json ... ```)
    cleaned = cleaned.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/```\s*$/i, '').trim();

    // 2. FIX LỖI CRITICAL: Xử lý n8n expression bị AI in ra nguyên văn gây lỗi JSON
    // Ví dụ: {{ $json.TongSoBinhLuan }} -> Thay thành 0 để JSON hợp lệ
    cleaned = cleaned.replace(/\{\{\s*[^}]+\s*\}\}/g, '0');

    // Lấy nội dung trong cặp ngoặc nhọn
    let jsonString = cleaned;
    if (!cleaned.startsWith('{')) {
      const match = cleaned.match(/\{[\s\S]*\}/);
      if (match) jsonString = match[0];
    }

    try {
      parsed = JSON.parse(jsonString);
    } catch (e) {
      console.error('Lỗi parse JSON:', e.message);
    }
  } else if (typeof rawOutput === 'object') {
    parsed = rawOutput;
  }

  // --- XỬ LÝ DỮ LIỆU ---

  // Chuẩn hóa mảng Chủ Đề
  let chuDeArray = [];
  const rawChuDe = getField(parsed, ['ChuDe', 'Chủ đề', 'topic'], '');
  if (Array.isArray(rawChuDe)) {
    chuDeArray = rawChuDe;
  } else if (typeof rawChuDe === 'string' && rawChuDe !== '') {
    chuDeArray = [rawChuDe];
  } else {
    chuDeArray = ['CHƯA XÁC ĐỊNH'];
  }

  // Tổng hợp lại thành object cuối cùng
  const result = {
    // Mapping: Lấy từ JSON AI sinh ra, nếu không có thì lấy thẳng từ input node trước
    NoiDungBaiViet: getField(parsed, ['NoiDung', 'NoiDungBaiViet', 'Nội dung bài viết'], getField(data, ['NoiDungBaiViet', 'TieuDe'], '')),
    URL: getField(parsed, ['URLBaiViet', 'URL', 'url'], getField(data, ['UrlBaiViet', 'URL'], '')),
    NgayDang: getField(parsed, ['NgayDang'], getField(data, ['NgayDang'], '')),

    // Các trường AI phân tích
    ChuDe: chuDeArray,
    LinhVuc: getField(parsed, ['LinhVuc', 'Lĩnh vực'], 'CHƯA XÁC ĐỊNH'),
    CoTiengLong_MiaMai: getField(parsed, ['CoTiengLong_MiaMai', 'coTiengLongMiaMai'], false) === true,
    PhanTramTieuCuc: Number(getField(parsed, ['PhanTramTieuCuc', 'phanTramTieuCuc'], 0)) || 0,
    DanhGia: getField(parsed, ['DanhGia', 'Đánh giá'], 'CHƯA XÁC ĐỊNH'),
    PhanTichBaiViet: getField(parsed, ['PhanTichBaiViet', 'Phân tích bài viết'], ''),
    LyDoDanhGia: getField(parsed, ['LyDoDanhGia', 'Lý do đánh giá'], ''),
    MucDoRuiRo: getField(parsed, ['MucDoRuiRo', 'Mức độ rủi ro'], 'CHƯA XÁC ĐỊNH'),
    DeXuatXuLy: getField(parsed, ['DeXuatXuLy', 'Đề xuất xử lý'], 'Không cần xử lý'),

    NgayXuLy: ngayXuLy
  };

  ketQua.push({ json: result });
}

return ketQua;

