// ==================== BÁO CÁO GIÁM SÁT MẠNG XÃ HỘI ====================
// Dành cho Đồ án tốt nghiệp - ĐH Cửu Long
// Xử lý dữ liệu đầu ra từ AI (dạng JSON như mẫu)

const ketQua = [];

// --- 1. Xác định tuần báo cáo (tuần hiện tại, bắt đầu từ thứ Hai) ---
const now = new Date();
const day = now.getDay(); // 0: CN, 1: T2, ..., 6: T7
const monday = new Date(now);
monday.setDate(now.getDate() - (day === 0 ? 6 : day - 1));
monday.setHours(0, 0, 0, 0);

const sunday = new Date(monday);
sunday.setDate(monday.getDate() + 6);
sunday.setHours(23, 59, 59, 999);

// Mã báo cáo: BC-YYYY-Wxx (dựa trên số tuần trong năm)
const weekNum = Math.ceil((monday - new Date(monday.getFullYear(), 0, 1)) / (7 * 24 * 60 * 60 * 1000));
const baoCaoID = `BC-${monday.getFullYear()}-W${weekNum}`;

// --- 2. Khởi tạo các biến thống kê ---
let tong = 0;
let tieuCucCount = 0;      // CoTiengLong_MiaMai = true
let tongPhanTramTieuCuc = 0; // tổng % tiêu cực để tính trung bình
let mucDoCao = 0;
let mucDoTrungBinh = 0;
let mucDoThap = 0;

// Lưu danh sách bài viết có rủi ro cao (để đưa ra đề xuất chi tiết)
let baiVietRuiRoCao = [];

// Lưu các đề xuất nổi bật (từ trường DeXuatXuLy)
let xuLyKhuyenNghi = new Set();

// --- 3. Duyệt từng bài viết trong input ---
$input.all().forEach(item => {
  const data = item.json;
  tong++;

  // Xác định tiêu cực dựa trên CoTiengLong_MiaMai (boolean) hoặc PhanTramTieuCuc > ngưỡng
  const coTieuCuc = data.CoTiengLong_MiaMai === true || (data.PhanTramTieuCuc > 50);
  if (coTieuCuc) tieuCucCount++;

  // Cộng dồn % tiêu cực (nếu có)
  const pTieuCuc = typeof data.PhanTramTieuCuc === 'number' ? data.PhanTramTieuCuc : 0;
  tongPhanTramTieuCuc += pTieuCuc;

  // Phân loại mức độ rủi ro
  const mucDo = (data.MucDoRuiRo || '').toString().toLowerCase();
  if (mucDo.includes('cao')) {
    mucDoCao++;
    // Lưu thông tin bài có rủi ro cao để báo cáo riêng
    baiVietRuiRoCao.push({
      TacGia: data.TacGia || 'Ẩn danh',
      NoiDungTomTat: (data.NoiDung || '').substring(0, 120) + '...',
      URL: data.URL,
      PhanTramTieuCuc: pTieuCuc,
      DeXuatXuLy: data.DeXuatXuLy || 'Chưa có đề xuất'
    });
  } else if (mucDo.includes('trung bình')) {
    mucDoTrungBinh++;
  } else {
    mucDoThap++;
  }

  // Thu thập các đề xuất xử lý (không trùng lặp)
  if (data.DeXuatXuLy && data.DeXuatXuLy.trim()) {
    xuLyKhuyenNghi.add(data.DeXuatXuLy.trim());
  }
});

// --- 4. Tính toán các chỉ số tổng hợp ---
const phanTramTieuCuc = tong > 0 ? ((tieuCucCount / tong) * 100).toFixed(1) : 0;
const diemTieuCucTB = tong > 0 ? (tongPhanTramTieuCuc / tong).toFixed(1) : 0;

// --- 5. Đánh giá mức độ cảnh báo chung ---
let canhBaoChung = '';
let mauSac = '';
if (phanTramTieuCuc >= 30 || mucDoCao > 3) {
  canhBaoChung = 'CẢNH BÁO CAO - Cần can thiệp ngay';
  mauSac = 'Đỏ';
} else if (phanTramTieuCuc >= 10 || mucDoCao > 0) {
  canhBaoChung = 'Theo dõi chặt - Có dấu hiệu tiêu cực';
  mauSac = 'Cam';
} else {
  canhBaoChung = 'Bình thường - Tiếp tục giám sát';
  mauSac = 'Xanh';
}

// --- 6. Tạo báo cáo kết quả ---
const baoCao = {
  // Thông tin báo cáo
  BaoCaoID: baoCaoID,
  TuNgay: monday.toISOString().split('T')[0],
  DenNgay: sunday.toISOString().split('T')[0],
  ThoiGianTao: new Date().toLocaleString('vi-VN'),

  // Thống kê số lượng
  TongBaiViet: tong,
  SoBaiCoDauHieuTieuCuc: tieuCucCount,
  PhanTramTieuCuc: parseFloat(phanTramTieuCuc),
  DiemTieuCucTrungBinh: parseFloat(diemTieuCucTB),

  // Phân bố mức độ rủi ro
  MucDoCao: mucDoCao,
  MucDoTrungBinh: mucDoTrungBinh,
  MucDoThap: mucDoThap,

  // Đánh giá
  CanhBao: canhBaoChung,
  MauCanhBao: mauSac,

  // Danh sách bài viết cần xử lý ngay (rủi ro cao)
  BaiVietRuiRoCao: baiVietRuiRoCao,

  // Các đề xuất xử lý tổng hợp (loại bỏ trùng)
  CacDeXuatXuLy: Array.from(xuLyKhuyenNghi).slice(0, 10),

  // Gợi ý hành động tiếp theo
  HanhDongGoiY: (
    mucDoCao > 0 ? `Có ${mucDoCao} bài viết mức độ ảnh hưởng CAO, cần phản hồi hoặc báo cáo lãnh đạo ngay. ` : ''
  ) + (
    tieuCucCount > 5 ? `Số lượng bài tiêu cực (${tieuCucCount}) vượt ngưỡng, cần họp rút kinh nghiệm.` : ''
  ) || 'Tiếp tục giám sát định kỳ.'
};

// --- 7. Trả về kết quả (dạng array chứa object json) ---
ketQua.push({ json: baoCao });
return ketQua;

