const items = $input.all();

console.log('=== BẮT ĐẦU KIỂM TRA TRÙNG LẶP ===');

// 1. Phân loại dữ liệu đầu vào
const oldArticles = [];  // Bài viết đã có trong Google Sheets
const newArticles = [];  // Bài viết mới từ webhook crawl

items.forEach(item => {
  const data = item.json;

  // Dữ liệu từ Google Sheets (đã lưu) - có trường URLBaiViet
  if (data.URLBaiViet) {
    oldArticles.push(data);
  } 
  // Dữ liệu mới từ crawl - có trường post_url
  else if (data.post_url) {
    newArticles.push(data);
  }
});

console.log(`📚 Số bài viết cũ (trong Sheets): ${oldArticles.length}`);
console.log(`🆕 Số bài viết mới (crawl được): ${newArticles.length}`);

// 2. Hàm chuẩn hóa URL để so sánh chính xác
function normalizeUrl(url) {
  if (!url || typeof url !== 'string') return '';
  return url
    .toLowerCase()                // chuyển về chữ thường
    .split('?')[0]                // bỏ query parameters (?fbclid=...)
    .replace(/\/$/, '')           // bỏ dấu / cuối cùng nếu có
    .trim();
}

// 3. Tạo Set chứa các URL đã tồn tại (từ Google Sheets)
const existingUrls = new Set();

oldArticles.forEach(article => {
  const link = normalizeUrl(article.URLBaiViet);
  if (link) {
    existingUrls.add(link);
  }
});

console.log(`🔗 Số URL đã tồn tại: ${existingUrls.size}`);

// 4. Lọc ra những bài viết mới chưa bị trùng
const uniqueArticles = [];

newArticles.forEach(article => {
