const ketQua = [];

for (const item of items) {
  const data = item.json;
  const ngayXuLy = new Date().toLocaleString('vi-VN');

  // Hàm lấy giá trị từ object với nhiều tên trường khả dụng
  const getField = (obj, possibleKeys, defaultValue = '') => {
    for (const key of possibleKeys) {
      if (obj[key] !== undefined && obj[key] !== null && obj[key] !== '') return obj[key];
    }
    return defaultValue;
  };

  // Lấy output từ AI Agent (thường nằm ở data.output hoặc data.text)
  let rawOutput = getField(data, ['output', 'text', 'message', 'content'], '');
  let parsed = {};

  if (rawOutput && typeof rawOutput === 'string' && rawOutput.trim() !== '') {
    let cleaned = rawOutput.trim();

    // Loại bỏ markdown code block ```json ... ``` hoặc ``` ... ```
    cleaned = cleaned.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/```\s*$/i, '').trim();

    // Nếu cleaned bắt đầu bằng '{' thì parse trực tiếp, nếu không thì tìm đoạn JSON trong chuỗi
    let jsonString = cleaned;
    if (!cleaned.startsWith('{')) {
      const match = cleaned.match(/\{[\s\S]*\}/);
      if (match) jsonString = match[0];
    }

    try {
      parsed = JSON.parse(jsonString);
    } catch (e) {
      console.error('Lỗi parse JSON lần 1:', e.message);
      // Fallback: Sửa lại chuỗi JSON bị lỗi gạch đầu dòng và thiếu ngoặc kép của AI
      try {
        let fixed = jsonString.replace(/^\s*-\s*(.*?):\s*(.*)$/gm, (match, key, value) => {
          // Xóa dấu phẩy hoặc ngoặc kép ở cuối nếu có
          let cleanValue = value.trim().replace(/,$/, '').replace(/"$/, '').replace(/^"/, '');

          // Nếu value là số thì không cần ngoặc kép
          if (!isNaN(cleanValue) && cleanValue !== '') {
            return `"${key.trim()}": ${cleanValue},`;
          }

          // Chuyển escape ngoặc kép bên trong chuỗi để tránh lỗi JSON
          cleanValue = cleanValue.replace(/"/g, '\\"');
          return `"${key.trim()}": "${cleanValue}",`;
        });

        // Xử lý dấu phẩy thừa ở cuối object (trước dấu đóng })
        fixed = fixed.replace(/,\s*\}/g, '}');

        parsed = JSON.parse(fixed);
      } catch (e2) {
        console.error('Lỗi fallback parse lần 2:', e2.message);
      }
    }
  } else if (typeof rawOutput === 'object') {
    // Nếu output đã là object thì dùng trực tiếp
    parsed = rawOutput;
  }

  // Xác định các trường với nhiều tên khả dụng
  const tacGia = getField(parsed, ['Tác giả', 'TacGia', 'author'], getField(data, ['Tác giả', 'TacGia', 'author'], ''));
  const noiDung = getField(parsed, ['Nội dung bài viết', 'NoiDung', 'content'], getField(data, ['Nội dung bài viết', 'NoiDung', 'content'], ''));
  const url = getField(parsed, ['URL', 'url', 'Url'], getField(data, ['URL', 'url', 'Url'], ''));
  const binhLuan = getField(parsed, ['Bình luận (đã gộp)', 'BinhLuan', 'comments'], getField(data, ['Bình luận (đã gộp)', 'BinhLuan', 'comments'], ''));
  const tongSoBinhLuan = parseInt(getField(parsed, ['Tổng số bình luận', 'TongSoBinhLuan', 'commentCount'], getField(data, ['Tổng số bình luận', 'TongSoBinhLuan', 'commentCount'], 0)), 10);

  // Trường ChuDe: có thể là mảng hoặc chuỗi
  let chuDeArray = [];
  const rawChuDe = getField(parsed, ['ChuDe', 'Chủ đề', 'topic'], getField(data, ['ChuDe', 'Chủ đề', 'topic'], ''));
  if (Array.isArray(rawChuDe)) {
    chuDeArray = rawChuDe;
  } else if (typeof rawChuDe === 'string' && rawChuDe !== '') {
    chuDeArray = [rawChuDe];
  } else {
    chuDeArray = ['CHƯA XÁC ĐỊNH'];
  }

  const result = {
    TacGia: tacGia,
    NoiDung: noiDung,
    URL: url,
    BinhLuan: binhLuan,
    TongSoBinhLuan: isNaN(tongSoBinhLuan) ? 0 : tongSoBinhLuan,
    ChuDe: chuDeArray,
    LinhVuc: getField(parsed, ['LinhVuc', 'Lĩnh vực', 'domain'], getField(data, ['LinhVuc', 'Lĩnh vực', 'domain'], 'CHƯA XÁC ĐỊNH')),
    CoTiengLong_MiaMai: getField(parsed, ['CoTiengLong_MiaMai', 'coTiengLongMiaMai', 'sarcasm'], getField(data, ['CoTiengLong_MiaMai', 'coTiengLongMiaMai', 'sarcasm'], false)) === true,
    PhanTramTieuCuc: Number(getField(parsed, ['PhanTramTieuCuc', 'phanTramTieuCuc', 'negativePercent'], getField(data, ['PhanTramTieuCuc', 'phanTramTieuCuc', 'negativePercent'], 0))) || 0,
    DanhGia: getField(parsed, ['DanhGia', 'Đánh giá', 'assessment'], getField(data, ['DanhGia', 'Đánh giá', 'assessment'], 'CHƯA XÁC ĐỊNH')),
    PhanTichBaiViet: getField(parsed, ['PhanTichBaiViet', 'Phân tích bài viết', 'postAnalysis'], getField(data, ['PhanTichBaiViet', 'Phân tích bài viết', 'postAnalysis'], '')),
    PhanTichBinhLuan: getField(parsed, ['PhanTichBinhLuan', 'Phân tích bình luận', 'commentAnalysis'], getField(data, ['PhanTichBinhLuan', 'Phân tích bình luận', 'commentAnalysis'], '')),
    LyDoDanhGia: getField(parsed, ['LyDoDanhGia', 'Lý do đánh giá', 'reason'], getField(data, ['LyDoDanhGia', 'Lý do đánh giá', 'reason'], '')),
    MucDoRuiRo: getField(parsed, ['MucDoRuiRo', 'Mức độ rủi ro', 'riskLevel'], getField(data, ['MucDoRuiRo', 'Mức độ rủi ro', 'riskLevel'], 'CHƯA XÁC ĐỊNH')),
    DeXuatXuLy: getField(parsed, ['DeXuatXuLy', 'Đề xuất xử lý', 'suggestion'], getField(data, ['DeXuatXuLy', 'Đề xuất xử lý', 'suggestion'], 'Không cần xử lý')),
    NgayXuLy: ngayXuLy
  };

  ketQua.push({ json: result });
}

return ketQua;

